import React, { useState } from 'react';
import BoxPedido from '../BoxPedido';
import * as C from './style';

function Column({ title, pedidos, produtos }) {

    const [ produto, setProduto ] = useState()

    if(pedidos.length > 0){
        return (
            <C.Coluna>
                <C.Titulo>
                    {title}            
                </C.Titulo>
                {pedidos.map( e => {

                        //console.log(e.carrinho);
                        const newCarrinho = JSON.parse(e.carrinho);
                        e.carrinho = newCarrinho
                        //console.log(produtos);
                        //produto = produtos.filter( i => i.idprodutos === 1)
                        (<BoxPedido produto={produtos.idprodutos} key={e.idpedidos} pedido={e}/>)
                    })}
            </C.Coluna>
        )
    }
}

export default Column
